public.example:
public class Main {
    public static void main(String[] args) {}
}

private.example:
public class Account {
    private double balance;
}

protected.example:
public class Base {
    protected int id;
}

class.example:
public class Point {
    int x, y;
}

abstract.example:
abstract class Shape {
    abstract double area();
}

static.example:
class MathUtils {
    static int square(int x) { return x * x; }
}
MathUtils.square(4);

this.example:
class Point {
    int x;
    Point(int x) { this.x = x; }
}

super.example:
class Dog extends Animal {
    Dog(String name) { super(name); }
}

extends.example:
class Dog extends Animal {
    void speak() { System.out.println('Woof!'); }
}

implements.example:
class Circle implements Shape {
    public double area() { return Math.PI * r * r; }
}

for-each.example:
int[] nums = {1, 2, 3};
for (int n : nums) {
    System.out.println(n);
}

do-while.example:
int n = 0;
do {
    System.out.println(n);
    n++;
} while (n < 3);

switch.example:
switch (day) {
    case 'M':
        System.out.println('Monday');
        break;
    default:
        System.out.println('Other');
}

break.example:
for (int i = 0; i < 10; i++) {
    if (i == 3) break;
    System.out.println(i);
}

continue.example:
for (int i = 0; i < 5; i++) {
    if (i % 2 == 0) continue;
    System.out.println(i);
}

return.example:
int square(int x) {
    return x * x;
}

try.example:
try {
    int x = 1 / 0;
} catch (ArithmeticException e) {
    System.out.println(e.getMessage());
}

throw.example:
if (age < 0) {
    throw new IllegalArgumentException('Age cannot be negative');
}

instanceof.example:
if (obj instanceof String) {
    System.out.println('It is a String');
}

generics.example:
class Box<T> {
    T value;
}
Box<String> box = new Box<>();
